import{_ as a,o,c as n,aw as e}from"./chunks/framework.DLufY-ao.js";const u=JSON.parse('{"title":"List (Список)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/data-structures/structures/list.md","filePath":"wiki/dev-commit/theory/data-structures/structures/list.md"}'),l={name:"wiki/dev-commit/theory/data-structures/structures/list.md"};function t(p,s,c,r,i,d){return o(),n("div",null,[...s[0]||(s[0]=[e('<h1 id="list-список" tabindex="-1">List (Список) <a class="header-anchor" href="#list-список" aria-label="Permalink to &quot;List (Список)&quot;">​</a></h1><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">List</p><ul><li><strong>List</strong> (Список) - представление пронумерованной последовательности значений, где одно и то же значение может присутствовать сколько угодно раз</li><li>Обычный список позволяет очень быстро получить доступ к памяти, поскольку вы уже знаете нужный адрес</li><li>У списков есть порядковые номера, поэтому можно вставлять значения в начало, середину и конец</li><li>Списки отлично справляются с быстрым доступом к элементам в своём конце и работой с ними. Однако, для элементов из начала или середины они не слишком хороши, так как приходится вручную обрабатывать адреса памяти</li></ul></div><h2 id="операции" tabindex="-1">Операции <a class="header-anchor" href="#операции" aria-label="Permalink to &quot;Операции&quot;">​</a></h2><h3 id="push-добавить-в-конец-pop-удалить-из-конца-o-1" tabindex="-1"><code>Push</code> (добавить в конец), <code>Pop</code> (удалить из конца) - <em>O(1)</em> <a class="header-anchor" href="#push-добавить-в-конец-pop-удалить-из-конца-o-1" aria-label="Permalink to &quot;`Push` (добавить в конец), `Pop` (удалить из конца) - _O(1)_&quot;">​</a></h3><blockquote><p>Являются простыми операциями, поскольку не затрагивают весь остальной список</p></blockquote><h3 id="unshift-добавить-в-начало-o-n" tabindex="-1"><code>Unshift</code> (добавить в начало) - <em>O(N)</em> <a class="header-anchor" href="#unshift-добавить-в-начало-o-n" aria-label="Permalink to &quot;`Unshift` (добавить в начало) - _O(N)_&quot;">​</a></h3><blockquote><p>Чтобы добавить новый элемент в начало списка, нужно освободить пространство для этого значения, сдвинув на один все последующие значения</p></blockquote><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-light vp-code" tabindex="0"><code><span class="line"><span style="color:#383A42;">[a, b, c, d, e]</span></span>\n<span class="line"><span style="color:#4078F2;"> 0</span><span style="color:#986801;">  1</span><span style="color:#986801;">  2</span><span style="color:#986801;">  3</span><span style="color:#986801;">  4</span></span>\n<span class="line"><span style="color:#4078F2;">  ⬊</span><span style="color:#50A14F;">  ⬊</span><span style="color:#50A14F;">  ⬊</span><span style="color:#50A14F;">  ⬊</span><span style="color:#50A14F;">  ⬊</span></span>\n<span class="line"><span style="color:#4078F2;">    1</span><span style="color:#986801;">  2</span><span style="color:#986801;">  3</span><span style="color:#986801;">  4</span><span style="color:#986801;">  5</span></span>\n<span class="line"><span style="color:#383A42;">[x, a, b, c, d, e]</span></span></code></pre></div><h3 id="shift-удалить-из-начала-o-n" tabindex="-1"><code>Shift</code> (удалить из начала) - <em>O(N)</em> <a class="header-anchor" href="#shift-удалить-из-начала-o-n" aria-label="Permalink to &quot;`Shift` (удалить из начала) - _O(N)_&quot;">​</a></h3><blockquote><p>Удаляем первое значение и затем сдвигаем каждый элемент списка на предшествующий адрес</p></blockquote><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-light vp-code" tabindex="0"><code><span class="line"><span style="color:#383A42;">[x, a, b, c, d, e]</span></span>\n<span class="line"><span style="color:#4078F2;">    1</span><span style="color:#986801;">  2</span><span style="color:#986801;">  3</span><span style="color:#986801;">  4</span><span style="color:#986801;">  5</span></span>\n<span class="line"><span style="color:#4078F2;">  ⬋</span><span style="color:#50A14F;">  ⬋</span><span style="color:#50A14F;">  ⬋</span><span style="color:#50A14F;">  ⬋</span><span style="color:#50A14F;">  ⬋</span></span>\n<span class="line"><span style="color:#4078F2;"> 0</span><span style="color:#986801;">  1</span><span style="color:#986801;">  2</span><span style="color:#986801;">  3</span><span style="color:#986801;">  4</span></span>\n<span class="line"><span style="color:#383A42;">[a, b, c, d, e]</span></span></code></pre></div>',12)])])}const y=a(l,[["render",t]]);export{u as __pageData,y as default};
